namespace sv_d8e90927364248de95f1134c025b89b9.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor);

using Microsoft.AspNetCore.Components;

namespace sv_d8e90927364248de95f1134c025b89b9.Services;

/// <summary>
/// Scoped service (per circuit) that holds the current theme state.
/// Components subscribe to OnChange; mutators call SetTheme/SetAccentColor
/// which updates both the service state and the CascadingValueSource.
/// </summary>
public class ThemeService : IDisposable
{
    private readonly CascadingValueSource<ThemeInfo> _cascadingSource;

    public ThemeService(CascadingValueSource<ThemeInfo> cascadingSource)
    {
        _cascadingSource = cascadingSource;
    }

    public Theme CurrentTheme { get; private set; } = Theme.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        CurrentTheme = theme;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        AccentColor = color;
        await NotifyAsync();
    }

    public async Task SetAllAsync(Theme theme, string accentColor)
    {
        CurrentTheme = theme;
        AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        var info = new ThemeInfo(CurrentTheme, AccentColor);
        await _cascadingSource.NotifyChangedAsync(info);
        OnChange?.Invoke();
    }

    public void Dispose()
    {
        OnChange = null;
    }
}

