    private async Task CycleThemeAsync()
    {
        var next = ThemeSvc.CurrentTheme switch
        {
            Theme.Light  => Theme.Dark,
            Theme.Dark   => Theme.System,
            _            => Theme.Light
        };
        await ThemeSvc.SetThemeAsync(next);
    }

    public void Dispose()
    {
        ThemeSvc.OnChange -= StateHasChanged;
    }
}

