@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Color scheme</label>
            <select class="form-select" value="@ThemeSvc.CurrentTheme"
                    @onchange="OnThemeChangedAsync">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent color</label>
            <input type="color" class="form-control form-control-color"
                   value="@ThemeSvc.AccentColor"
                   @onchange="OnAccentChangedAsync" />
        </div>

        <p class="text-muted mt-3">
            Current: <strong>@ThemeSvc.CurrentTheme</strong> /
            <span style="color: @ThemeSvc.AccentColor;">@ThemeSvc.AccentColor</span>
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += StateHasChanged;
    }

    private async Task OnThemeChangedAsync(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            await ThemeSvc.SetThemeAsync(theme);
        }
    }

    private async Task OnAccentChangedAsync(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrWhiteSpace(color))
        {
            await ThemeSvc.SetAccentColorAsync(color);
        }
    }

    public void Dispose()
    {
        ThemeSvc.OnChange -= StateHasChanged;
    }
}

